"use client";

import { useAuth } from "@/context/AuthContext";
import { auth } from "@/lib/firebase";
import Image from "next/image";

export default function Topbar() {
    const { user } = useAuth();

    return (
        <header style={{
            height: '64px',
            backgroundColor: 'var(--surface)',
            borderBottom: '1px solid var(--border)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            padding: '0 2rem',
            position: 'sticky',
            top: 0,
            zIndex: 5
        }}>
            <div style={{ fontWeight: 600, color: 'var(--text-main)' }}>
                {/* Breadcrumbs or Page Title could go here */}
                Overview
            </div>

            <div style={{ display: 'flex', alignItems: 'center', gap: '1.5rem' }}>
                <button style={{ background: 'none', border: 'none', fontSize: '1.2rem', cursor: 'pointer' }} title="Notifications">
                    🔔
                </button>

                <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                    <div style={{ textAlign: 'right', lineHeight: 1.2 }}>
                        <div style={{ fontSize: '0.875rem', fontWeight: 600 }}>{user?.displayName}</div>
                        <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>Requester</div>
                    </div>
                    <div style={{
                        width: '36px',
                        height: '36px',
                        borderRadius: '50%',
                        backgroundColor: 'var(--accent)',
                        color: 'white',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: '1rem',
                        fontWeight: 'bold',
                        overflow: 'hidden'
                    }}>
                        {user?.photoURL ? (
                            <img src={user.photoURL} alt="Profile" style={{ width: '100%', height: '100%' }} />
                        ) : (
                            user?.displayName?.[0] || 'U'
                        )}
                    </div>
                    <button
                        onClick={() => auth.signOut()}
                        style={{
                            background: 'none',
                            border: 'none',
                            color: 'var(--text-secondary)',
                            fontSize: '0.875rem',
                            cursor: 'pointer',
                            marginLeft: '0.5rem'
                        }}
                    >
                        Sign Out
                    </button>
                </div>
            </div>
        </header>
    );
}
