"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";

const menuItems = [
    { name: "Dashboard", href: "/dashboard", icon: "📊" },
    { name: "Requisitions", href: "/dashboard/requisitions", icon: "📝" },
    { name: "Vendors", href: "/dashboard/vendors", icon: "🏢" },
    { name: "Purchase Orders", href: "/dashboard/purchase-orders", icon: "📦" },
    { name: "Invoices", href: "/dashboard/invoices", icon: "🧾" },
    { name: "Budgets", href: "/dashboard/budgets", icon: "💰" },
    { name: "Settings", href: "/dashboard/settings", icon: "⚙️" },
];

export default function Sidebar() {
    const pathname = usePathname();

    return (
        <aside style={{
            width: '260px',
            height: '100vh',
            backgroundColor: 'var(--surface)',
            borderRight: '1px solid var(--border)',
            position: 'fixed',
            left: 0,
            top: 0,
            display: 'flex',
            flexDirection: 'column',
            zIndex: 10
        }}>
            <div style={{ padding: '1.5rem', borderBottom: '1px solid var(--border)' }}>
                <h2 style={{ fontSize: '1.25rem', fontWeight: 'bold', color: 'var(--primary)' }}>SpendManager</h2>
            </div>

            <nav style={{ flex: 1, padding: '1rem', overflowY: 'auto' }}>
                <ul style={{ listStyle: 'none' }}>
                    {menuItems.map((item) => {
                        const isActive = pathname === item.href;
                        return (
                            <li key={item.name} style={{ marginBottom: '0.5rem' }}>
                                <Link
                                    href={item.href}
                                    style={{
                                        display: 'flex',
                                        alignItems: 'center',
                                        gap: '0.75rem',
                                        padding: '0.75rem 1rem',
                                        borderRadius: 'var(--radius-md)',
                                        color: isActive ? 'var(--accent)' : 'var(--text-secondary)',
                                        backgroundColor: isActive ? '#eff6ff' : 'transparent', // Light blue bg for active
                                        fontWeight: isActive ? 600 : 400,
                                        transition: 'all 0.2s',
                                    }}
                                >
                                    <span>{item.icon}</span>
                                    {item.name}
                                </Link>
                            </li>
                        );
                    })}
                </ul>
            </nav>

            <div style={{ padding: '1.5rem', borderTop: '1px solid var(--border)' }}>
                <div style={{ fontSize: '0.875rem', color: 'var(--text-secondary)' }}>
                    &copy; 2026 SpendManager
                </div>
            </div>
        </aside>
    );
}
